// ❌ Weak — setter exposes internal state directly
public class Matricula {
    private String situacao;
    public void setSituacao(String s) { this.situacao = s; }
}

// ✅ Strong — behavior method protects invariants
public class Matricula {
    private SituacaoMatricula situacao;

    public void confirmar() {
        if (this.situacao != PENDENTE) {
            throw new IllegalStateException("Can only confirm PENDING enrollment");
        }
        this.situacao = ATIVA;
        this.dataConfirmacao = LocalDate.now();
    }
}

// Instead of: BaseReport → PdfReport → StudentPdfReport → ...

public class ReportGenerator {
    private final DataSource dataSource;
    private final Formatter formatter;
    private final Exporter exporter;

    public ReportGenerator(DataSource ds, Formatter fmt, Exporter exp) {
        this.dataSource = ds;
        this.formatter = fmt;
        this.exporter = exp;
    }

    public byte[] generate(ReportRequest request) {
        var data = dataSource.fetch(request);
        var formatted = formatter.format(data);
        return exporter.export(formatted);
    }
}

// Usage: combine freely
new ReportGenerator(studentDataSource, tableFormatter, pdfExporter);
new ReportGenerator(turmaDataSource, chartFormatter, excelExporter);
